import{_ as i,o as s,c as e,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"gtquiver/faq.md","filePath":"gtquiver/faq.md","lastUpdated":1783966097000}'),l={name:"gtquiver/faq.md"};function p(n,a,h,d,o,r){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>GT 系列插件交流群：<code>985955382</code></p><h2 id="插件没有启用" tabindex="-1">插件没有启用 <a class="header-anchor" href="#插件没有启用" aria-label="Permalink to &quot;插件没有启用&quot;">​</a></h2><ul><li>确认 GTCore 已经正常启用。</li><li>确认 <code>plugins</code> 目录中只有一个 GTQuiver Jar。</li><li>更换 Jar 后完整重启，不使用热加载。</li><li>从控制台最早出现的 GTQuiver 报错开始看。</li></ul><h2 id="gtq-reload-失败" tabindex="-1">/gtq reload 失败 <a class="header-anchor" href="#gtq-reload-失败" aria-label="Permalink to &quot;/gtq reload 失败&quot;">​</a></h2><p>常见原因：</p><ul><li>YAML 缩进或引号错误。</li><li>箭袋 ID、箭 ID 大小写重复。</li><li>当前版本不存在配置中的材质。</li><li><code>game-modes</code> 写错。</li><li><code>lore-regex</code> 正则错误。</li><li><code>attribute-bridge.provider</code> 不是 <code>CA</code>、<code>AP</code>、<code>BOTH</code>、<code>NONE</code>。</li><li><code>provider-item</code> 对应物品不存在。</li></ul><p>修正后执行 <code>/gtq reload</code>，再用 <code>/gtq list</code> 查看已加载 ID。</p><h2 id="主手右键空气打不开" tabindex="-1">主手右键空气打不开 <a class="header-anchor" href="#主手右键空气打不开" aria-label="Permalink to &quot;主手右键空气打不开&quot;">​</a></h2><p>正确操作是主手拿箭袋，按住 Shift 右键空气或方块。</p><p>副手不会打开。仍无反应时检查箭袋权限、世界、游戏模式和 GTCore 条件。</p><h2 id="地上的箭袋无法拾取" tabindex="-1">地上的箭袋无法拾取 <a class="header-anchor" href="#地上的箭袋无法拾取" aria-label="Permalink to &quot;地上的箭袋无法拾取&quot;">​</a></h2><p>先看箭袋 Lore 是否显示了其他玩家的绑定信息。绑定箭袋只能由绑定玩家拾取和使用，管理员权限不会绕过绑定。</p><p>需要公共箭袋时重新发放非绑定版本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq give 玩家 箭袋ID 1 unbound</span></span></code></pre></div><p>玩家改名不影响绑定，归属仍按 UUID 判断。</p><h2 id="背包没有箭时无法拉弓" tabindex="-1">背包没有箭时无法拉弓 <a class="header-anchor" href="#背包没有箭时无法拉弓" aria-label="Permalink to &quot;背包没有箭时无法拉弓&quot;">​</a></h2><ul><li>箭袋需要放在 <code>settings.equipped-slots</code> 指定位置。</li><li>普通弓只能使用普通箭、药水箭、光灵箭。</li><li>烟花只供弩使用。</li><li>玩家需要满足箭袋权限和使用条件。</li><li>背包内存在其他兼容箭时，会按原版规则使用背包箭。</li></ul><p>执行 <code>/gtq debug 玩家</code> 可查看当前箭袋和第一支可用箭。</p><h2 id="轻点右键后背包出现箭" tabindex="-1">轻点右键后背包出现箭 <a class="header-anchor" href="#轻点右键后背包出现箭" aria-label="Permalink to &quot;轻点右键后背包出现箭&quot;">​</a></h2><p>确认使用当前版本 GTQuiver，并完整重启服务器。</p><p>仍能复现时开启 <code>settings.debug</code>，保留一次操作产生的日志，同时检查反作弊、背包同步、物品锁定类插件。</p><h2 id="箭袋不扣箭" tabindex="-1">箭袋不扣箭 <a class="header-anchor" href="#箭袋不扣箭" aria-label="Permalink to &quot;箭袋不扣箭&quot;">​</a></h2><ul><li>创造模式默认不消耗。</li><li>普通原版箭会遵守无限附魔。</li><li>背包已有箭时，可能消耗的是背包箭。</li></ul><p>关闭无限附魔处理：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">settings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  respect-infinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h2 id="彩色公式不生效" tabindex="-1">彩色公式不生效 <a class="header-anchor" href="#彩色公式不生效" aria-label="Permalink to &quot;彩色公式不生效&quot;">​</a></h2><p>实际伤害需要写在 <code>effects.formula-damage</code>：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">effects</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  formula-damage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;7物理伤害: &amp;c+20000&quot;</span></span></code></pre></div><p>下面只是一行显示 Lore，不会自动增加 GTQuiver 伤害：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">item</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  lore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;7造成伤害20000点&quot;</span></span></code></pre></div><p>带计算公式的写法：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">formula-damage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;7物理伤害: &amp;c+{calc:120+%player_level%*2}&quot;</span></span></code></pre></div><p>公式仍无结果时开启 debug，检查 PAPI 变量是否返回数字。</p><h2 id="ap-箭拿在手里有属性-射出去没有" tabindex="-1">AP 箭拿在手里有属性，射出去没有 <a class="header-anchor" href="#ap-箭拿在手里有属性-射出去没有" aria-label="Permalink to &quot;AP 箭拿在手里有属性，射出去没有&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">attribute-bridge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AP&quot;</span></span></code></pre></div><p>默认值是 <code>CA</code>，AP 服务器需要手动修改。修改后完整重启，再执行 <code>/gtq debug 玩家</code> 查看 AP 是否已连接。</p><h2 id="ca-箭没有属性" tabindex="-1">CA 箭没有属性 <a class="header-anchor" href="#ca-箭没有属性" aria-label="Permalink to &quot;CA 箭没有属性&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">attribute-bridge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CA&quot;</span></span></code></pre></div><p>确认箭本身符合当前 CA 的物品属性格式，并用 <code>/gtq debug 玩家</code> 查看 CA 状态。</p><h2 id="ca-和-ap-同时安装后伤害翻倍" tabindex="-1">CA 和 AP 同时安装后伤害翻倍 <a class="header-anchor" href="#ca-和-ap-同时安装后伤害翻倍" aria-label="Permalink to &quot;CA 和 AP 同时安装后伤害翻倍&quot;">​</a></h2><p>检查是否使用：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;BOTH&quot;</span></span></code></pre></div><p>只使用一套属性时改为 <code>CA</code> 或 <code>AP</code>。</p><h2 id="自动换箭后属性没有变化" tabindex="-1">自动换箭后属性没有变化 <a class="header-anchor" href="#自动换箭后属性没有变化" aria-label="Permalink to &quot;自动换箭后属性没有变化&quot;">​</a></h2><p>确认：</p><ul><li><code>attribute-bridge.provider</code> 选择正确。</li><li>两种箭的实际 Lore、属性或 NBT 不同。</li><li>使用当前版本 GTQuiver。</li><li>其他武器或属性插件没有另外缓存属性。</li></ul><p>问题日志中同时附上 <code>/gtq debug 玩家</code> 输出。</p><h2 id="弓左键伤害异常" tabindex="-1">弓左键伤害异常 <a class="header-anchor" href="#弓左键伤害异常" aria-label="Permalink to &quot;弓左键伤害异常&quot;">​</a></h2><p>默认禁止弓和弩近战：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">combat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  block-bow-melee</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>需要允许弓弩左键伤害时改为 <code>false</code>。GTQuiver 自定义箭始终不能手持近战。</p><h2 id="射出的箭无法拾取" tabindex="-1">射出的箭无法拾取 <a class="header-anchor" href="#射出的箭无法拾取" aria-label="Permalink to &quot;射出的箭无法拾取&quot;">​</a></h2><p>默认配置就是禁止回收：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">arrow-recovery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  allow-non-infinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>允许回收：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">arrow-recovery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  allow-non-infinity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>无限弓射出的箭、创造模式未消耗的箭仍不可拾取。</p><h2 id="拾取后没有进入箭袋" tabindex="-1">拾取后没有进入箭袋 <a class="header-anchor" href="#拾取后没有进入箭袋" aria-label="Permalink to &quot;拾取后没有进入箭袋&quot;">​</a></h2><ul><li><code>allow-non-infinity</code> 需要为 <code>true</code>。</li><li>箭袋需要装备在配置槽位。</li><li>箭要符合箭袋 <code>accept</code>。</li><li>箭袋需要有空位或可合并堆叠。</li><li>玩家自动收箭需要开启。</li></ul><p>有权限时执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtq autopickup on</span></span></code></pre></div><p>箭袋无法接收时，箭进入普通背包。</p><h2 id="gtq-autopickup-没有权限" tabindex="-1">/gtq autopickup 没有权限 <a class="header-anchor" href="#gtq-autopickup-没有权限" aria-label="Permalink to &quot;/gtq autopickup 没有权限&quot;">​</a></h2><p>权限默认不授予：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtquiver.command.autopickup</span></span></code></pre></div><p>LuckPerms：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/lp user 玩家 permission set gtquiver.command.autopickup true</span></span></code></pre></div><h2 id="papi-变量返回未选择" tabindex="-1">PAPI 变量返回未选择 <a class="header-anchor" href="#papi-变量返回未选择" aria-label="Permalink to &quot;PAPI 变量返回未选择&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%gtquiver_current_arrow%</span></span>
<span class="line"><span>%gtquiver_current_arrow_colored%</span></span></code></pre></div><p>没有装备箭袋、箭袋为空、箭袋不可用时都会返回 <code>未选择</code>。</p><p>同时确认 PlaceholderAPI 已启用，并在安装或更新后完整重启服务器。</p><h2 id="shift-左键不能切换箭" tabindex="-1">Shift+左键不能切换箭 <a class="header-anchor" href="#shift-左键不能切换箭" aria-label="Permalink to &quot;Shift+左键不能切换箭&quot;">​</a></h2><p>需要同时满足：</p><ul><li>玩家处于潜行状态。</li><li>左键空气或方块。</li><li>已装备可用箭袋。</li><li>箭袋内至少有两种不同箭。</li></ul><p>完整物品相同、只有数量不同的箭算同一种。</p><h2 id="跨服后箭袋无法读取" tabindex="-1">跨服后箭袋无法读取 <a class="header-anchor" href="#跨服后箭袋无法读取" aria-label="Permalink to &quot;跨服后箭袋无法读取&quot;">​</a></h2><ul><li>跨服背包插件需要保留完整物品 NBT。</li><li>两端 GTCore、GTQuiver 版本保持一致。</li><li>两端箭袋 ID 和容量保持一致。</li><li>目标服容量不能小于箭袋原容量。</li><li>自定义箭使用的物品库和属性插件保持一致。</li></ul>`,78)])])}const u=i(l,[["render",p]]);export{k as __pageData,u as default};
